module divide_by_8(  
    input clk,  
    input reset,  
    output reg out  
);  
    reg [2:0] counter_value;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            counter_value <= 3'b000;  
            out <= 1'b0;  
        end else begin  
            counter_value <= counter_value + 1;  
            if (counter_value == 3'b100) // When counter_value reaches 4  
                out <= 1'b1;  
            else  
                out <= 1'b0;  
        end  
    end  
endmodule
